using UnityEngine;
using UnityEngine.SceneManagement;
using System.Collections;

public class MenuManager : MonoBehaviour
{
    public GameObject mainMenu;
    public GameObject settingsMenu;
    public GameObject creditsMenu;
    public GameObject pauseMenu;

    public Animator transitionAnimator;
    public string transitionAnimationName = "Fade";
    public float transitionDuration = 1f;

    private bool isPaused = false;
    private bool isTransitioning = false;

    void Start()
    {
        // Show main menu at start
        ShowMainMenu();

        // Unpause if game was paused
        Time.timeScale = 1f;
    }

    void Update()
    {
        // Pause with Escape key
        if (Input.GetKeyDown(KeyCode.Escape))
        {
            if (isPaused)
            {
                ResumeGame();
            }
            else
            {
                PauseGame();
            }
        }
    }

    // ----- Main Menu -----
    public void ShowMainMenu()
    {
        mainMenu.SetActive(true);
        settingsMenu.SetActive(false);
        creditsMenu.SetActive(false);
        pauseMenu.SetActive(false);
        Time.timeScale = 1f;
        isPaused = false;
    }

    public void StartGame()
    {
        if (!isTransitioning)
        {
            StartCoroutine(LoadSceneWithTransition("GameScene"));
        }
    }

    public void ShowSettings()
    {
        mainMenu.SetActive(false);
        settingsMenu.SetActive(true);
        creditsMenu.SetActive(false);
    }

    public void ShowCredits()
    {
        mainMenu.SetActive(false);
        settingsMenu.SetActive(false);
        creditsMenu.SetActive(true);
    }

    public void BackToMainMenu()
    {
        ShowMainMenu();
    }

    public void QuitGame()
    {
        #if UNITY_EDITOR
        UnityEditor.EditorApplication.isPlaying = false;
        #else
        Application.Quit();
        #endif
    }

    // ----- Pause Menu -----
    public void PauseGame()
    {
        if (SceneManager.GetActiveScene().name != "MenuScene")
        {
            isPaused = true;
            Time.timeScale = 0f;
            pauseMenu.SetActive(true);
        }
    }

    public void ResumeGame()
    {
        isPaused = false;
        Time.timeScale = 1f;
        pauseMenu.SetActive(false);
    }

    public void RestartGame()
    {
        Time.timeScale = 1f;
        isPaused = false;
        StartCoroutine(LoadSceneWithTransition(SceneManager.GetActiveScene().name));
    }

    public void GoToMainMenu()
    {
        Time.timeScale = 1f;
        isPaused = false;
        StartCoroutine(LoadSceneWithTransition("MenuScene"));
    }

    // ----- Scene Transitions -----
    IEnumerator LoadSceneWithTransition(string sceneName)
    {
        isTransitioning = true;

        // Play fade out animation
        if (transitionAnimator != null)
        {
            transitionAnimator.SetTrigger("FadeOut");
        }

        // Wait for animation to finish
        yield return new WaitForSeconds(transitionDuration);

        // Load scene
        SceneManager.LoadScene(sceneName);

        // Play fade in animation (after scene loads)
        if (transitionAnimator != null)
        {
            transitionAnimator.SetTrigger("FadeIn");
        }

        isTransitioning = false;
    }

    // ----- Utility Methods -----
    public bool IsPaused()
    {
        return isPaused;
    }

    public void ToggleFullscreen()
    {
        Screen.fullScreen = !Screen.fullScreen;
    }

    public void SetQuality(int qualityIndex)
    {
        QualitySettings.SetQualityLevel(qualityIndex);
    }

    public void SetVolume(float volume)
    {
        AudioListener.volume = volume;
    }
}

