using UnityEngine;
using UnityEngine.SceneManagement;

public class MenuError : MonoBehaviour
{
    void Start()
    {
        // Forgot to check scene name
        if (SceneManager.GetActiveScene().name == "GameScene")
        {
            // This never runs because scene name is case-sensitive!
            Debug.Log("Game started!");
        }
    }
}

phase2.explanation:
Scene names are case-sensitive. "GameScene" is different from "gamescene".

**The fix:**
```csharp
if (SceneManager.GetActiveScene().name == "GameScene")  // Exact case
{
    Debug.Log("Game started!");
}
```

